"use strict";(self.webpackChunkclassroom_scrapper_site=self.webpackChunkclassroom_scrapper_site||[]).push([[2830],{5794(e){e.exports=JSON.parse('{"tag":{"label":"Search","permalink":"/tags/search","allTagsPath":"/tags","count":3,"items":[{"id":"ES119/Module 1/Lec_06_A Search Algorithm and Game Theory Basics","title":"A* Search Algorithm and Game Theory Basics","description":"The A\\\\* search algorithm is a cornerstone of pathfinding and graph traversal, widely used in artificial intelligence and computer science for its efficiency and optimality under certain conditions. It builds upon ideas from Breadth-First Search (BFS) and Dijkstra\'s algorithm by incorporating a heuristic function to guide its search more effectively.","permalink":"/ES119/Module 1/Lec_06_A Search Algorithm and Game Theory Basics"},{"id":"ES119/Module 1/Lecture4_AgentEnvironment","title":"Agent and Environment Representation for Pathfinding","description":"Introduction to Pathfinding Applications","permalink":"/ES119/Module 1/Lecture4_AgentEnvironment"},{"id":"ES119/Module 1/Lecture7_alphabeta","title":"Alpha-Beta Pruning","description":"In adversarial search, the Minimax algorithm provides a theoretical framework for optimal decision-making in zero-sum games. However, its computational complexity renders it impractical for games with large search spaces. Alpha-Beta Pruning is an optimization that drastically reduces the number of nodes evaluated by the Minimax algorithm without affecting the final decision.","permalink":"/ES119/Module 1/Lecture7_alphabeta"}],"unlisted":false}}')}}]);